function e(e,n){const t=document.getElementById(e),a=document.getElementById(n);t&&a&&t.addEventListener("submit",e=>{e.preventDefault();const n=new FormData(t),i=String(n.get("email")??"").trim(),s=String(n.get("senha")??"");i&&s?(a.innerHTML='<div class="text-muted">Entrando...</div>',async function(e){const n=await fetch("usuarios/logica/login_usuario.php",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(e)});return await n.json()}({email:i,senha:s}).then(e=>{e.sucesso?(a.innerHTML=`<div class="alert alert-success mb-0">${e.mensagem}</div>`,e.sucesso&&e.usuario&&(window.location.href="home.php")):a.innerHTML=`<div class="alert alert-danger mb-0">${e.mensagem}</div>`}).catch(()=>{a.innerHTML='<div class="alert alert-danger mb-0">Erro inesperado ao comunicar com o servidor.</div>'})):a.innerHTML='<div class="alert alert-warning mb-0">Preencha e-mail e senha.</div>'})}document.addEventListener("DOMContentLoaded",()=>{e("form-login","resultado-login")});
